let firstRec = FortyTwoCrunchAPIProtectionV2_CL
| where TimeGenerated >= ago(5m) 
| project-away NonBlockingMode, SourcePort, DestinationPort, Query, ApiId, RequestHeader, ResponseHeader, Errors, EventType, Uuid
| where InstanceName == "Instance_6" and UriPath has "/api/login?user=" and Status in (200, 403);
